import pytest
import requests

def test_decision_table_role_and_assignment_combinations(
    patient_role_token,
    unassigned_clinician_token,
    dt_patient_id,
    base_url,
):
    url = f"{base_url}/Patient/{dt_patient_id}"

    r1 = requests.get(
        url, headers={"Authorization": f"Bearer {patient_role_token}"}
    )
    assert r1.status_code == 403, f"Rule1 expected 403, got {r1.status_code}"

    r2 = requests.get(
        url, headers={"Authorization": f"Bearer {unassigned_clinician_token}"}
    )
    assert r2.status_code == 403, f"Rule2 expected 403, got {r2.status_code}"

    r3 = requests.get(url)
    assert r3.status_code == 401, f"Rule3 expected 401, got {r3.status_code}"
